const port = Number(Bun.env.PORT ?? 3000);

type Event = { id: number; message: string; created_at: number };

const events: Event[] = [];
let nextId = 1;

function encodeCursor(id: number): string {
  return Buffer.from(String(id), "utf8").toString("base64url");
}

function decodeCursor(token: string): number | null {
  let decoded: string;
  try {
    decoded = Buffer.from(token, "base64url").toString("utf8");
  } catch {
    return null;
  }
  if (!/^\d+$/.test(decoded)) return null;
  const value = Number(decoded);
  if (!Number.isInteger(value) || value <= 0) return null;
  return value;
}

function parseLimit(raw: string | null): number | null {
  if (raw === null) return 10;
  if (!/^-?\d+$/.test(raw.trim())) return null;
  const value = Number(raw);
  if (!Number.isInteger(value) || value <= 0) return null;
  return Math.min(value, 100);
}

Bun.serve({
  port,
  async fetch(request) {
    const url = new URL(request.url);

    if (request.method === "POST" && url.pathname === "/events") {
      let body: unknown;
      try {
        body = await request.json();
      } catch {
        return Response.json({ error: "invalid_body" }, { status: 422 });
      }
      const record = body as Record<string, unknown> | null;
      if (!record || typeof record.message !== "string") {
        return Response.json({ error: "invalid_body" }, { status: 422 });
      }
      const event: Event = { id: nextId++, message: record.message, created_at: Date.now() };
      events.push(event);
      return Response.json(event, { status: 201 });
    }

    if (request.method === "GET" && url.pathname === "/events") {
      const limit = parseLimit(url.searchParams.get("limit"));
      if (limit === null) {
        return Response.json({ error: "invalid_limit" }, { status: 400 });
      }

      const cursorParam = url.searchParams.get("cursor");
      let boundary = Infinity;
      if (cursorParam !== null) {
        const decoded = decodeCursor(cursorParam);
        if (decoded === null) {
          return Response.json({ error: "invalid_cursor" }, { status: 400 });
        }
        boundary = decoded;
      }

      // Newest-first: iterate ids descending, take those with id < boundary.
      const items: Event[] = [];
      for (let i = events.length - 1; i >= 0 && items.length < limit; i -= 1) {
        if (events[i]!.id < boundary) {
          items.push(events[i]!);
        }
      }

      // Emit a cursor whenever the page was filled to `limit`. A page that
      // returns fewer than `limit` items is the final page (null cursor). At an
      // exact boundary (a full page that exhausts the feed) the cursor leads to
      // an empty next page with a null cursor, which is the documented contract.
      let next_cursor: string | null = null;
      if (items.length === limit) {
        next_cursor = encodeCursor(items[items.length - 1]!.id);
      }

      return Response.json({ items, next_cursor }, { status: 200 });
    }

    return Response.json({ error: "not_found" }, { status: 404 });
  },
});

